function MoodJournal() {
  const moods = [
    { emoji: '😊', label: 'Good', color: '#22c55e' },
    { emoji: '😐', label: 'Okay', color: '#eab308' },
    { emoji: '😔', label: 'Low', color: '#ef4444' }
  ];
  const [entries, setEntries] = React.useState([
    { mood: 0, note: 'Had a great workout!', date: new Date().toLocaleDateString() }
  ]);
  const [selected, setSelected] = React.useState(0);
  const [note, setNote] = React.useState('');
  const addEntry = () => {
    if (!note.trim()) return;
    setEntries([{ mood: selected, note: note.trim(), date: new Date().toLocaleDateString() }, ...entries]);
    setNote('');
  };
  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#fff', borderRadius: 12, height: '100%', boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <h3 style={{ margin: '0 0 12px 0', fontSize: 16, color: '#222' }}>Mood Journal</h3>
      <div style={{ display: 'flex', gap: 12, marginBottom: 12, justifyContent: 'center' }}>
        {moods.map((m, i) => (
          <button key={i} onClick={() => setSelected(i)} style={{ flex: 1, padding: '10px 0', borderRadius: 10, border: selected === i ? '2px solid ' + m.color : '2px solid transparent', background: selected === i ? m.color + '15' : '#f8f8f8', cursor: 'pointer', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 4 }}>
            <span style={{ fontSize: 28 }}>{m.emoji}</span>
            <span style={{ fontSize: 12, fontWeight: 500, color: selected === i ? m.color : '#666' }}>{m.label}</span>
          </button>
        ))}
      </div>
      <textarea value={note} onChange={(e) => setNote(e.target.value)} placeholder="How are you feeling?" style={{ resize: 'none', height: 60, padding: 10, borderRadius: 10, border: '1px solid #ddd', fontFamily: 'inherit', fontSize: 13, marginBottom: 10 }} />
      <button onClick={addEntry} style={{ padding: '8px 0', borderRadius: 8, border: 'none', background: '#4f46e5', color: '#fff', cursor: 'pointer', fontFamily: 'inherit', fontWeight: 500, marginBottom: 12 }}>Log Entry</button>
      <div style={{ overflow: 'auto', flex: 1 }}>
        {entries.map((e, i) => (
          <div key={i} style={{ padding: 10, borderRadius: 8, background: '#f8f8f8', marginBottom: 8 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 4 }}>
              <span style={{ fontSize: 18 }}>{moods[e.mood].emoji}</span>
              <span style={{ fontSize: 11, color: '#999' }}>{e.date}</span>
            </div>
            <p style={{ margin: 0, fontSize: 13, color: '#444' }}>{e.note}</p>
          </div>
        ))}
      </div>
    </div>
  );
}
render(<MoodJournal/>);
